Here are the public test cases for feature3_optional_metadata_payload:
{
  "description": "Build a task scheduling payload that includes optional metadata, repeat interval, policies, constraints, and user input data.",
  "cases": [
    {
      "input": {
        "debug": true,
        "work": {
          "uniqueName": "uniqueName",
          "taskName": "taskName",
          "tag": "tag",
          "repeatEverySeconds": 1,
          "collisionPolicy": "replace",
          "initialDelaySeconds": 2,
          "constraints": {
            "network": "connected",
            "batteryNotLow": false,
            "charging": true,
            "deviceIdle": true,
            "storageNotLow": false
          },
          "retryBackoffPolicy": "linear",
          "retryBackoffDelaySeconds": 3,
          "inputData": {
            "key": "value"
          }
        }
      },
      "expected_output": "{\"isInDebugMode\":true,\"uniqueName\":\"uniqueName\",\"taskName\":\"taskName\",\"tag\":\"tag\",\"frequency\":1,\"existingWorkPolicy\":\"replace\",\"initialDelaySeconds\":2,\"networkType\":\"connected\",\"requiresBatteryNotLow\":false,\"requiresCharging\":true,\"requiresDeviceIdle\":true,\"requiresStorageNotLow\":false,\"backoffPolicyType\":\"linear\",\"backoffDelayInMilliseconds\":3000,\"outOfQuotaPolicy\":null,\"inputData\":\"{\\\"key\\\":\\\"value\\\"}\"}\n"
    }
  ]
}

